import{_ as s,o as e,c as n,a}from"./app.919094ca.js";const h=JSON.parse('{"title":"Checking the VNode type","description":"","frontmatter":{},"headers":[],"relativePath":"guide/checking-the-vnode-type.md"}'),o={name:"guide/checking-the-vnode-type.md"},l=a(`<h1 id="checking-the-vnode-type" tabindex="-1">Checking the VNode type <a class="header-anchor" href="#checking-the-vnode-type" aria-hidden="true">#</a></h1><p>Vue has a built-in function, <a href="https://vuejs.org/api/render-function.html#isvnode" target="_blank" rel="noreferrer"><code>isVNode()</code></a>, for testing whether something is a VNode.</p><p>Most of the helpers provided by <code>vue-vnode-utils</code> require a callback that will be passed eligible VNodes. These will always be full VNodes, so it isn&#39;t necessary to use <code>isVNode()</code> within those callbacks.</p><p>It is common to want to handle different types of VNode differently inside the callback. For example, you might want to detect text VNodes. The type of a VNode can be checked using <code>getType()</code>:</p><div class="language-js"><button class="copy"></button><span class="lang">js</span><pre><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> children </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">addProps</span><span style="color:#A6ACCD;">(slotVNodes</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">vnode</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">switch</span><span style="color:#F07178;"> (</span><span style="color:#82AAFF;">getType</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">vnode</span><span style="color:#F07178;">)) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">case</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">component</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#89DDFF;">      </span><span style="color:#676E95;">// ...</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">case</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">element</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#89DDFF;">      </span><span style="color:#676E95;">// ...</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">case</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">text</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#89DDFF;">      </span><span style="color:#676E95;">// ...</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">case</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">comment</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#89DDFF;">      </span><span style="color:#676E95;">//</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><p>In addition to the values shown above, <code>getType()</code> can also return <code>&#39;static&#39;</code>, <code>&#39;fragment&#39;</code> and <code>undefined</code>. Of those 3 values, only <code>&#39;static&#39;</code> can be encountered in the callbacks, but in practice that shouldn&#39;t happen if the VNode came from a slot.</p><p>The value passed to <code>getType()</code> doesn&#39;t have to be a fully instantiated VNode. It also supports being passed any value that can be converted to a VNode. So, for example, a string would be considered a text node. If you need to check that something really is a VNode then use <code>isVNode()</code>, but in practice this shouldn&#39;t be necessary for the values passed to callbacks by <code>vue-vnode-utils</code>.</p><p>There are also helpers for checking an individual type:</p><ul><li><a href="/vue-vnode-utils/api.html#iscomponent">isComponent()</a></li><li><a href="/vue-vnode-utils/api.html#iselement">isElement()</a></li><li><a href="/vue-vnode-utils/api.html#istext">isText()</a></li><li><a href="/vue-vnode-utils/api.html#iscomment">isComment()</a></li><li><a href="/vue-vnode-utils/api.html#isfragment">isFragment()</a></li><li><a href="/vue-vnode-utils/api.html#isstatic">isStatic()</a></li></ul><p>For example:</p><div class="language-js"><button class="copy"></button><span class="lang">js</span><pre><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> children </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">replaceChildren</span><span style="color:#A6ACCD;">(slotVNodes</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">vnode</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">if</span><span style="color:#F07178;"> (</span><span style="color:#82AAFF;">isText</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">vnode</span><span style="color:#F07178;">) </span><span style="color:#89DDFF;">||</span><span style="color:#F07178;"> </span><span style="color:#82AAFF;">isComment</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">vnode</span><span style="color:#F07178;">)) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#676E95;">// ...</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><p>It should be noted that most of the callbacks can be pre-filtered by passing <a href="/vue-vnode-utils/api.html#iterationoptions"><code>IterationOptions</code></a>, so it&#39;s only necessary to do explicit checks if the callback needs to handle multiple types.</p><p>Component VNodes can be split into two further categories using <a href="/vue-vnode-utils/api.html#isstatefulcomponent">isStatefulComponent()</a> and <a href="/vue-vnode-utils/api.html#isfunctionalcomponent">isFunctionalComponent()</a>. The component itself is available via the VNode&#39;s <code>type</code> property. For an element VNode the <code>type</code> will be the tag name.</p><p><code>getText()</code> can be used to read the text from a text node. As well as text VNodes, it also considers strings and numbers to be valid text nodes, consistent with <code>isText()</code>. If the passed value is not a valid text node then <code>undefined</code> will be returned.</p>`,14),t=[l];function p(c,r,i,d,y,F){return e(),n("div",null,t)}const u=s(o,[["render",p]]);export{h as __pageData,u as default};
